using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _classifierService;

    public TicketClassifierController(TicketClassifierService classifierService)
    {
        _classifierService = classifierService;
    }

    [HttpPost("predict")]
    public ActionResult<PredictionResult> Predict([FromBody] TicketInput input)
    {
        if (string.IsNullOrWhiteSpace(input.Subject) || string.IsNullOrWhiteSpace(input.Description))
            return BadRequest("Subject and Description are required.");

        if (input.Priority < 1 || input.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifierService.Predict(input);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResult> GetMetrics()
    {
        return Ok(_classifierService.GetEvaluationMetrics());
    }
}

